234	                    if (typeId == null) {
235	                        ctxt.reportPropertyInputMismatch(_beanType, extProp.getProperty().getName(),
236	"Invalid default type id for property '%s': `null` returned by TypeIdResolver",
237	                                extProp.getTypePropertyName());
238	                    }
239	                }
240	            } else if (_tokens[i] == null) {
241	                SettableBeanProperty prop = extProp.getProperty();
242	
243	                if (prop.isRequired() ||
244	                        ctxt.isEnabled(DeserializationFeature.FAIL_ON_MISSING_EXTERNAL_TYPE_ID_PROPERTY)) {
245	                    ctxt.reportPropertyInputMismatch(bean.getClass(), prop.getName(),
246	                            "Missing property '%s' for external type id '%s'",
247	                            prop.getName(), extProp.getTypePropertyName());
